#include <string>
#include <algorithm>
#include <vector>

using namespace std;

class Solution {
private:
    int calculateCost(const std::string& s, const std::string& target) {
        int cost = 0;
        for (size_t i = 0; i < s.length(); ++i) {
            if (s[i] != target[i]) {
                cost++;
            }
        }
        return cost;
    }

public:
    long long solve(std::string s) {
        int n = s.length();
        if (n < 3) {
            return 0;
        }

        // Coherent strings must be of the form 0^a, 1^b, 0^a1, or 10^b.
        // We calculate the minimum flips needed to achieve these four archetypal forms.

        // 1. Target 0^N
        std::string T0(n, '0');
        long long cost0 = calculateCost(s, T0);

        // 2. Target 1^N
        std::string T1(n, '1');
        long long cost1 = calculateCost(s, T1);

        // 3. Target 0^(N-1)1
        std::string T_0_N_1(n - 1, '0');
        T_0_N_1 += '1';
        long long cost_0_N_1 = calculateCost(s, T_0_N_1);

        // 4. Target 10^(N-1)
        std::string T_1_0_N_1 = "1";
        T_1_0_N_1.append(n - 1, '0');
        long long cost_1_0_N_1 = calculateCost(s, T_1_0_N_1);

        return std::min({cost0, cost1, cost_0_N_1, cost_1_0_N_1});
    }
};

// Wrapper to fit the required signature if necessary, though the class structure is often preferred in competitive programming.
long long solve(std::string s) {
    Solution sol;
    return sol.solve(s);
}

